-- =========================================================================
-- TRENDLOOP DATABASE SCHEMA MIGRATION
-- Project: Gen-Z Trends & Discovery Platform
-- Target: Supabase (Postgres)
-- =========================================================================

-- Enable UUID extension if not enabled
create extension if not exists "uuid-ossp";

-- =========================================================================
-- 1. TABLES DEFINITIONS
-- =========================================================================

-- Categories & Subcategories
create table public.categories (
  id uuid primary key default uuid_generate_v4(),
  slug text not null unique,
  name text not null,
  description text,
  parent_id uuid references public.categories(id) on delete set null
);

-- Products Catalog
create table public.products (
  id uuid primary key default uuid_generate_v4(),
  slug text not null unique,
  name text not null,
  description text,
  category_id uuid not null references public.categories(id) on delete restrict,
  subcategory_id uuid references public.categories(id) on delete restrict,
  price numeric not null,
  currency text not null default 'INR',
  brand text not null,
  images jsonb not null default '[]'::jsonb, -- array of {url, alt, order}
  features jsonb not null default '[]'::jsonb, -- array of strings
  pros jsonb not null default '[]'::jsonb, -- array of strings
  cons jsonb not null default '[]'::jsonb, -- array of strings
  is_featured boolean not null default false,
  is_trending boolean not null default false,
  trending_score numeric not null default 0,
  view_count bigint not null default 0,
  save_count bigint not null default 0,
  share_count bigint not null default 0,
  click_count bigint not null default 0,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

-- Tags System
create table public.tags (
  id uuid primary key default uuid_generate_v4(),
  name text not null unique,
  slug text not null unique
);

create table public.product_tags (
  product_id uuid not null references public.products(id) on delete cascade,
  tag_id uuid not null references public.tags(id) on delete cascade,
  primary key (product_id, tag_id)
);

-- Affiliate Links
create table public.affiliate_links (
  id uuid primary key default uuid_generate_v4(),
  product_id uuid not null references public.products(id) on delete cascade,
  retailer text not null, -- 'amazon' | 'flipkart' | 'myntra' | etc.
  raw_url text not null,  -- Raw URL, protected by RLS
  is_active boolean not null default true
);

-- User Profiles (Linked to Supabase Auth)
create table public.users (
  id uuid primary key references auth.users(id) on delete cascade,
  username text not null unique,
  display_name text,
  avatar_url text,
  bio text,
  role text not null default 'user', -- 'user' | 'admin'
  created_at timestamptz not null default now()
);

-- Pinterest-Style Boards
create table public.boards (
  id uuid primary key default uuid_generate_v4(),
  user_id uuid not null references public.users(id) on delete cascade,
  name text not null,
  slug text not null,
  description text,
  is_public boolean not null default true,
  cover_image text,
  created_at timestamptz not null default now()
);

-- Board Items (Pins)
create table public.board_items (
  id uuid primary key default uuid_generate_v4(),
  board_id uuid not null references public.boards(id) on delete cascade,
  product_id uuid not null references public.products(id) on delete cascade,
  note text,
  added_at timestamptz not null default now()
);

-- Saved Products (Likes)
create table public.saved_products (
  user_id uuid not null references public.users(id) on delete cascade,
  product_id uuid not null references public.products(id) on delete cascade,
  saved_at timestamptz not null default now(),
  primary key (user_id, product_id)
);

-- Product Views Tracking
create table public.product_views (
  id uuid primary key default uuid_generate_v4(),
  product_id uuid not null references public.products(id) on delete cascade,
  user_id uuid references public.users(id) on delete set null,
  session_id text not null,
  viewed_at timestamptz not null default now()
);

-- Affiliate redirectional Click events logs
create table public.click_events (
  id uuid primary key default uuid_generate_v4(),
  product_id uuid not null references public.products(id) on delete cascade,
  affiliate_link_id uuid not null references public.affiliate_links(id) on delete cascade,
  user_id uuid references public.users(id) on delete set null,
  session_id text not null,
  referrer text,
  utm_source text,
  utm_medium text,
  utm_campaign text,
  clicked_at timestamptz not null default now()
);

-- Content / Buying Guides Hub
create table public.guides (
  id uuid primary key default uuid_generate_v4(),
  slug text not null unique,
  title text not null,
  body_markdown text not null,
  cover_image text,
  related_product_ids jsonb not null default '[]'::jsonb, -- Array of product IDs/UUIDs
  seo_title text,
  seo_description text,
  published_at timestamptz not null default now()
);

-- Newsletter Subscribers
create table public.newsletter_subscribers (
  id uuid primary key default uuid_generate_v4(),
  email text not null unique,
  subscribed_at timestamptz not null default now(),
  source text not null default 'unknown'
);

-- =========================================================================
-- 2. INDEXES FOR PERFORMANCE & SCALABILITY
-- =========================================================================
create index idx_products_slug on public.products(slug);
create index idx_products_category on public.products(category_id);
create index idx_products_subcategory on public.products(subcategory_id);
create index idx_products_trending on public.products(trending_score desc);
create index idx_products_created on public.products(created_at desc);

create index idx_categories_parent on public.categories(parent_id);
create index idx_affiliate_links_prod on public.affiliate_links(product_id);
create index idx_boards_user on public.boards(user_id);
create index idx_board_items_board on public.board_items(board_id);
create index idx_saved_products_user on public.saved_products(user_id);
create index idx_click_events_product on public.click_events(product_id);
create index idx_guides_slug on public.guides(slug);
create index idx_users_username on public.users(username);

-- =========================================================================
-- 3. TRIGGERS & AUTOMATION FUNCTIONS
-- =========================================================================

-- Trigger function: Update updated_at timestamp
create or replace function public.update_modified_column()
returns trigger as $$
begin
  new.updated_at = now();
  return new;
end;
$$ language plpgsql;

create trigger update_products_modtime
  before update on public.products
  for each row execute procedure public.update_modified_column();

-- Trigger function: Auto-create User Profile on Auth signup
create or replace function public.handle_new_user()
returns trigger as $$
declare
  new_username text;
begin
  -- Generate unique username from email
  new_username := coalesce(
    new.raw_user_meta_data->>'username', 
    split_part(new.email, '@', 1)
  );
  
  -- Add a random suffix if username is already taken
  if exists (select 1 from public.users where username = new_username) then
    new_username := new_username || '_' || substring(md5(random()::text) from 1 for 4);
  end if;

  values (
    new.id,
    new_username,
    coalesce(new.raw_user_meta_data->>'display_name', split_part(new.email, '@', 1)),
    coalesce(new.raw_user_meta_data->>'avatar_url', 'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=150&auto=format&fit=crop&q=80'),
    'Gen-Z Trend Curator',
    'user'
  );
  return new;
end;
$$ language plpgsql security definer;

create trigger on_auth_user_created
  after insert on auth.users
  for each row execute procedure public.handle_new_user();

-- Trigger function: Automatically update save count on products
create or replace function public.update_product_save_count()
returns trigger as $$
begin
  if tg_op = 'INSERT' then
    update public.products
    set save_count = save_count + 1
    where id = new.product_id;
    return new;
  elsif tg_op = 'DELETE' then
    update public.products
    set save_count = greatest(0, save_count - 1)
    where id = old.product_id;
    return old;
  end if;
  return null;
end;
$$ language plpgsql;

create trigger on_product_saved
  after insert or delete on public.saved_products
  for each row execute procedure public.update_product_save_count();

-- Trigger function: Automatically update click count on products when logs are added
create or replace function public.update_product_click_count()
returns trigger as $$
begin
  update public.products
  set click_count = click_count + 1
  where id = new.product_id;
  return new;
end;
$$ language plpgsql;

create trigger on_affiliate_click
  after insert on public.click_events
  for each row execute procedure public.update_product_click_count();

-- Trigger function: Automatically update views count on products when logs are added
create or replace function public.update_product_view_count()
returns trigger as $$
begin
  update public.products
  set view_count = view_count + 1
  where id = new.product_id;
  return new;
end;
$$ language plpgsql;

create trigger on_product_viewed
  after insert on public.product_views
  for each row execute procedure public.update_product_view_count();

-- =========================================================================
-- 4. ROW-LEVEL SECURITY (RLS) POLICIES
-- =========================================================================

-- Enable RLS on all tables
alter table public.categories enable row level security;
alter table public.products enable row level security;
alter table public.tags enable row level security;
alter table public.product_tags enable row level security;
alter table public.affiliate_links enable row level security;
alter table public.users enable row level security;
alter table public.boards enable row level security;
alter table public.board_items enable row level security;
alter table public.saved_products enable row level security;
alter table public.product_views enable row level security;
alter table public.click_events enable row level security;
alter table public.guides enable row level security;
alter table public.newsletter_subscribers enable row level security;

-- Admin Helper checks
create or replace function public.is_admin()
returns boolean as $$
begin
  return exists (
    select 1 from public.users
    where id = auth.uid() and role = 'admin'
  );
end;
$$ language plpgsql security definer;

-- 4.1 public readable catalog tables (Admin writable only)
create policy "Categories are publicly readable." on public.categories for select to public using (true);
create policy "Categories are writable only by admin." on public.categories for all to authenticated using (public.is_admin());

create policy "Products are publicly readable." on public.products for select to public using (true);
create policy "Products are writable only by admin." on public.products for all to authenticated using (public.is_admin());

create policy "Tags are publicly readable." on public.tags for select to public using (true);
create policy "Tags are writable only by admin." on public.tags for all to authenticated using (public.is_admin());

create policy "Product tags are publicly readable." on public.product_tags for select to public using (true);
create policy "Product tags are writable only by admin." on public.product_tags for all to authenticated using (public.is_admin());

create policy "Guides are publicly readable." on public.guides for select to public using (true);
create policy "Guides are writable only by admin." on public.guides for all to authenticated using (public.is_admin());

-- 4.2 Affiliate Links: PUBLIC CANNOT READ RAW_URL directly (prevent scraping)
create policy "Affiliate links are hidden from public." on public.affiliate_links for select to public using (false);
-- Only authenticated Admins can see raw affiliate links
create policy "Affiliate links are visible to admins." on public.affiliate_links for select to authenticated using (public.is_admin());
create policy "Affiliate links are manageable by admins." on public.affiliate_links for all to authenticated using (public.is_admin());

-- 4.3 Users (Curators Profiles)
create policy "Profiles are publicly readable." on public.users for select to public using (true);
create policy "Users can update their own profile." on public.users for update to authenticated using (auth.uid() = id);
create policy "Admins can update all profiles." on public.users for all to authenticated using (public.is_admin());

-- 4.4 Boards (Pinterest collections)
create policy "Public boards are visible to everyone." on public.boards for select to public using (is_public = true or auth.uid() = user_id);
create policy "Users can insert their own boards." on public.boards for insert to authenticated with check (auth.uid() = user_id);
create policy "Users can update/delete their own boards." on public.boards for all to authenticated using (auth.uid() = user_id);

-- 4.5 Board Items (Pins)
create policy "Board items are readable if board is accessible." on public.board_items for select to public 
  using (exists (select 1 from public.boards b where b.id = board_id and (b.is_public = true or b.user_id = auth.uid())));
create policy "Users can pin to their own boards." on public.board_items for insert to authenticated 
  with check (exists (select 1 from public.boards b where b.id = board_id and b.user_id = auth.uid()));
create policy "Users can delete pins from their own boards." on public.board_items for delete to authenticated 
  using (exists (select 1 from public.boards b where b.id = board_id and b.user_id = auth.uid()));

-- 4.6 Saved Products (Heart Likes)
create policy "Saves are visible to owner." on public.saved_products for select to authenticated using (auth.uid() = user_id);
create policy "Users can save products." on public.saved_products for insert to authenticated with check (auth.uid() = user_id);
create policy "Users can delete saved products." on public.saved_products for delete to authenticated using (auth.uid() = user_id);

-- 4.7 Click events & views logs (Anonymous write-only, Admin read-only)
create policy "Click events can be created by anyone." on public.click_events for insert to public with check (true);
create policy "Click events can only be read by admins." on public.click_events for select to authenticated using (public.is_admin());

create policy "Views can be logged by anyone." on public.product_views for insert to public with check (true);
create policy "Views can only be read by admins." on public.product_views for select to authenticated using (public.is_admin());

-- 4.8 Newsletter Subscribers
create policy "Subscribers can sign up anonymously." on public.newsletter_subscribers for insert to public with check (true);
create policy "Subscribers can only be read by admins." on public.newsletter_subscribers for select to authenticated using (public.is_admin());


