INSERT INTO public.products (id, slug, name, description, category_id, subcategory_id, price, brand, images, features, pros, cons, is_featured, is_trending, trending_score, created_at, updated_at) VALUES
  ('a3c8e42f-7c1a-47a2-bd32-ef0816cfbc1a', 'heavyweight-boxy-hoodie', 'Heavyweight Boxy Hoodie', '450GSM ultra-thick loopback cotton hoodie. Slightly cropped body with dropped shoulders and double-lined hood for the perfect slouchy silhouette.', 'c4c23f72-7cb6-49a3-a7a2-f674681643ab', 'd0b2f7a1-cb9e-4e4b-bbd8-4f81a8b1c1e0', 1610, 'AESTHETIX', '[{"url":"https://images.unsplash.com/photo-1556911220-e15b29be8c8f?w=600&auto=format&fit=crop&q=80","alt":"Heavyweight Boxy Hoodie Image 1","order":0},{"url":"https://images.unsplash.com/photo-1543163521-1bf539c55dd2?w=600&auto=format&fit=crop&q=80","alt":"Heavyweight Boxy Hoodie Image 2","order":1},{"url":"https://images.unsplash.com/photo-1620799140408-edc6dcb6d633?w=600&auto=format&fit=crop&q=80","alt":"Heavyweight Boxy Hoodie Image 3","order":2},{"url":"https://images.unsplash.com/photo-1512436991641-6745cdb1723f?w=600&auto=format&fit=crop&q=80","alt":"Heavyweight Boxy Hoodie Image 4","order":3}]'::jsonb, '["450GSM Organic Cotton","Preshrunk vintage wash","No drawstring hood design","Ribbed side panels"]'::jsonb, '["Thick structured drape","Excellent warmth","Premium heavy feel"]'::jsonb, '["Slightly short fit for tall people","Takes longer to dry due to density"]'::jsonb, true, true, 8829, '2026-06-21T18:36:07.626Z', '2026-06-21T18:36:07.626Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000002', 'vintage-wash-utility-tee', 'Vintage Wash Utility Tee', 'Relaxed fit 280GSM heavy tee featuring a distressed screenprint logo and double-stitched collar. Hand-faded charcoal dye makes each shirt unique.', 'c4c23f72-7cb6-49a3-a7a2-f674681643ab', 'c4c23f72-7cb6-49a3-a7a2-f674681643ac', 850, 'NO-SIGNAL', '[{"url":"https://images.unsplash.com/photo-1521572267360-ee0c2909d518?w=600&auto=format&fit=crop&q=80","alt":"Vintage Wash Utility Tee Image 1","order":0},{"url":"https://images.unsplash.com/photo-1503342217505-b0a15ec3261c?w=600&auto=format&fit=crop&q=80","alt":"Vintage Wash Utility Tee Image 2","order":1},{"url":"https://images.unsplash.com/photo-1583743814966-8936f5b7be1a?w=600&auto=format&fit=crop&q=80","alt":"Vintage Wash Utility Tee Image 3","order":2}]'::jsonb, '["280GSM Cotton","Distressed neck detailing","Pigment-dyed for vintage look","Eco-friendly screen-printing"]'::jsonb, '["Extremely soft feel","Durable thick collar","Unique custom wash color"]'::jsonb, '["Hand-wash recommended to keep print","Slight color run on first wash"]'::jsonb, false, true, 6627, '2026-06-20T03:18:28.548Z', '2026-06-20T03:18:28.548Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000003', 'retro-runner-sneakers-v2', 'Retro Runner Sneakers V2', 'Crafted with suede overlays, open-cell mesh underlays, and a distressed pre-yellowed midsole for that retro 90s aesthetic.', 'c4c23f72-7cb6-49a3-a7a2-f674681643ab', 'a981fae8-cc4a-442a-a719-86f76c1251e0', 4250, 'HYPELAB', '[{"url":"https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 Image 1","order":0},{"url":"https://images.unsplash.com/photo-1595950653106-6c9ebd614d3a?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 Image 2","order":1},{"url":"https://images.unsplash.com/photo-1549298916-b41d501d3772?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 Image 3","order":2},{"url":"https://images.unsplash.com/photo-1606107557195-0e29a4b5b4aa?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 Image 4","order":3}]'::jsonb, '["Premium calf suede","Breathable nylon mesh panels","EVA shock-absorbing sole","Reflective 3M safety piping"]'::jsonb, '["Extremely comfortable for walking","Perfect aesthetic retro shape","Breathable mesh"]'::jsonb, '["Suede gets ruined in the rain","Expensive price point"]'::jsonb, true, true, 6382, '2026-06-21T02:41:19.911Z', '2026-06-21T02:41:19.911Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000004', 'oversized-cargo-sweatpants', 'Oversized Cargo Sweatpants', 'Thick fleece pants with a wide leg opening, utility side pockets, and toggle cuffs to shift between straight leg and cinched style.', 'c4c23f72-7cb6-49a3-a7a2-f674681643ab', 'd0b2f7a1-cb9e-4e4b-bbd8-4f81a8b1c1e0', 1360, 'AESTHETIX', '[{"url":"https://images.unsplash.com/photo-1620799140408-edc6dcb6d633?w=600&auto=format&fit=crop&q=80","alt":"Oversized Cargo Sweatpants Image 1","order":0},{"url":"https://images.unsplash.com/photo-1556911220-e15b29be8c8f?w=600&auto=format&fit=crop&q=80","alt":"Oversized Cargo Sweatpants Image 2","order":1},{"url":"https://images.unsplash.com/photo-1543163521-1bf539c55dd2?w=600&auto=format&fit=crop&q=80","alt":"Oversized Cargo Sweatpants Image 3","order":2},{"url":"https://images.unsplash.com/photo-1620799140408-edc6dcb6d633?w=600&auto=format&fit=crop&q=80","alt":"Oversized Cargo Sweatpants Image 4","order":3},{"url":"https://images.unsplash.com/photo-1512436991641-6745cdb1723f?w=600&auto=format&fit=crop&q=80","alt":"Oversized Cargo Sweatpants Image 5","order":4}]'::jsonb, '["380GSM fleece-lined cotton","Dual cargo side flap pockets","Toggle hem drawstrings","Embroidered tonal branding"]'::jsonb, '["Warm fleece interior","Very versatile hem styling","Deep pockets"]'::jsonb, '["Runs quite large","Fleece sheds slightly inside during initial wear"]'::jsonb, false, false, 559, '2026-06-22T07:59:20.205Z', '2026-06-22T07:59:20.205Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000005', 'q1-pro-custom-keyboard', 'Q1 Pro Custom Keyboard', '75% layout QMK/VIA wireless mechanical keyboard with full CNC aluminum body, double-gasket design, and hot-swappable switches.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'd881abf8-cdca-412a-a119-96f76c1262d0', 14020, 'Keychron', '[{"url":"https://images.unsplash.com/photo-1618384887929-16ec33fab9ef?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard Image 1","order":0},{"url":"https://images.unsplash.com/photo-1587829741301-dc798b83add3?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard Image 2","order":1},{"url":"https://images.unsplash.com/photo-1626908013351-800ddd734b8a?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard Image 3","order":2}]'::jsonb, '["Full CNC aluminum body","Wireless Bluetooth & 2.4G","Hot-swappable keys (3pin/5pin)","Screw-in PCB stabilizers"]'::jsonb, '["Immaculate heavy build quality","Satisfying deep ''thocky'' acoustic profile","Fully customizable keymap via VIA"]'::jsonb, '["Very heavy to carry around","High price barrier"]'::jsonb, true, true, 3110, '2026-06-22T09:25:26.305Z', '2026-06-22T09:25:26.305Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000006', 'minimal-felt-desk-pad-medium', 'Minimal Felt Desk Pad (Medium)', 'Made of 100% natural Merino wool felt with a non-slip cork base. Prevents desk scratches while adding acoustic dampening and a clean workspace texture.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'c51fa8b8-cffa-4f2a-8119-a6f76c1281e0', 1100, 'GRAIN & COLO', '[{"url":"https://images.unsplash.com/photo-1632292224971-0d45778b3002?w=600&auto=format&fit=crop&q=80","alt":"Minimal Felt Desk Pad (Medium) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1616440347437-b1c73416efc2?w=600&auto=format&fit=crop&q=80","alt":"Minimal Felt Desk Pad (Medium) Image 2","order":1}]'::jsonb, '["100% Merino Wool felt","4mm thickness","Eco-friendly non-slip cork backing","Stitched anti-fray borders"]'::jsonb, '["Very clean visual look","Dampens keyboard typing sounds","Comfortable skin contact"]'::jsonb, '["Wool is scratchy for sensitive skin","Cannot wash in washing machine"]'::jsonb, false, true, 3156, '2026-06-19T21:34:42.225Z', '2026-06-19T21:34:42.225Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000007', 'retro-rgb-led-monitor-lightbar', 'Retro RGB LED Monitor Lightbar', 'Asymmetric screen lighting that eliminates glare. Features a smart wireless dial to control brightness and color temperature on the fly.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3d', 2120, 'LUMEX', '[{"url":"https://images.unsplash.com/photo-1550745165-9bc0b252726f?w=600&auto=format&fit=crop&q=80","alt":"Retro RGB LED Monitor Lightbar Image 1","order":0},{"url":"https://images.unsplash.com/photo-1563089145-599997674d42?w=600&auto=format&fit=crop&q=80","alt":"Retro RGB LED Monitor Lightbar Image 2","order":1}]'::jsonb, '["Asymmetric optical design","USB-C powered","Wireless desktop controller dial","Backlight ambient RGB projector"]'::jsonb, '["Saves desk space","No direct light shines on screen","Wireless dial is very smooth"]'::jsonb, '["Struggles to fit on curved monitors","Dial batteries need replacement yearly"]'::jsonb, true, true, 4025, '2026-06-19T19:46:14.251Z', '2026-06-19T19:46:14.251Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000008', 'studio-sound-pro-headphones', 'Studio Sound Pro Headphones', 'Closed-back studio monitoring headphones with flat response curves, 45mm drivers, and plush memory foam earcups for long audio editing sessions.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3c', 10190, 'AUDIO-TECH', '[{"url":"https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones Image 1","order":0},{"url":"https://images.unsplash.com/photo-1546435770-a3e426bf472b?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones Image 2","order":1},{"url":"https://images.unsplash.com/photo-1484704849700-f032a568e944?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones Image 3","order":2}]'::jsonb, '["45mm large-aperture drivers","90-degree swiveling earcups","Detachable cables included","Plush memory foam pads"]'::jsonb, '["Accurate, non-colored sound profile","Comfortable head clamping pressure","Foldable travel design"]'::jsonb, '["Sound is analytical (not bass-boosted)","Plastic build feels slightly squeaky"]'::jsonb, false, true, 7441, '2026-06-20T15:16:32.624Z', '2026-06-20T15:16:32.624Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000009', 'neo-tokyo-cyberpunk-bomber-jacket', 'Neo-Tokyo Cyberpunk Bomber Jacket', 'Sleek water-resistant bomber featuring kanji embroidery, neon interior lining, and heavy-duty utility clips. Cyberpunk vibes for street fashion.', 'e10a6e3d-0453-4bf8-b98a-54c330f81d11', 'e10a6e3d-0453-4bf8-b98a-54c330f81d12', 2970, 'TOKYO-DRIP', '[{"url":"https://images.unsplash.com/photo-1543163521-1bf539c55dd2?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket Image 1","order":0},{"url":"https://images.unsplash.com/photo-1521572267360-ee0c2909d518?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket Image 2","order":1},{"url":"https://images.unsplash.com/photo-1503342217505-b0a15ec3261c?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket Image 3","order":2},{"url":"https://images.unsplash.com/photo-1583743814966-8936f5b7be1a?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket Image 4","order":3}]'::jsonb, '["Nylon outer shell","Embroidered back kanji","Dual utility metal clip straps","Insulated neon orange lining"]'::jsonb, '["Water-resistant utility outer","Bold premium embroidery","Inside zip pockets"]'::jsonb, '["Quite warm, not suitable for hot summers","Embroidery needs care while washing"]'::jsonb, true, false, 1778, '2026-06-22T02:07:46.872Z', '2026-06-22T02:07:46.872Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000010', 'limited-edition-mecha-action-figure', 'Limited Edition Mecha Action Figure', 'Highly articulated 1/144 scale metal composite action figure. Incredible paint detail, customizable weapon loadouts, and a custom display stand.', 'e10a6e3d-0453-4bf8-b98a-54c330f81d11', 'e18d6e3f-0463-4bf8-b98a-54d330f81c99', 7650, 'BANDAI', '[{"url":"https://images.unsplash.com/photo-1607604276583-eef5d076aa5f?w=600&auto=format&fit=crop&q=80","alt":"Limited Edition Mecha Action Figure Image 1","order":0},{"url":"https://images.unsplash.com/photo-1534447677768-be436bb09401?w=600&auto=format&fit=crop&q=80","alt":"Limited Edition Mecha Action Figure Image 2","order":1}]'::jsonb, '["Diecast metal and ABS build","1/144 custom scale","20+ articulation joints","LED eye illumination"]'::jsonb, '["Metal joints ensure solid posing","Incredible museum-grade paintwork","Exquisite collectors packaging"]'::jsonb, '["Very small delicate parts","Fragile antennas"]'::jsonb, true, true, 4038, '2026-06-22T06:34:12.069Z', '2026-06-22T06:34:12.069Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000011', 'manga-panels-acrylic-wall-frame', 'Manga Panels Acrylic Wall Frame', 'High-resolution printed acrylic glass displaying classic retro manga pages. Double-layered float design for a sleek 3D shadow effect.', 'e10a6e3d-0453-4bf8-b98a-54c330f81d11', 'e10a6e3d-0453-4bf8-b98a-54c330f81d13', 680, 'TOKYO-DRIP', '[{"url":"https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800&auto=format&fit=crop&q=80","alt":"Manga Panels Acrylic Wall Frame Image 1","order":0},{"url":"https://images.unsplash.com/photo-1513694203232-719a280e022f?w=600&auto=format&fit=crop&q=80","alt":"Manga Panels Acrylic Wall Frame Image 2","order":1},{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Manga Panels Acrylic Wall Frame Image 3","order":2},{"url":"https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=600&auto=format&fit=crop&q=80","alt":"Manga Panels Acrylic Wall Frame Image 4","order":3},{"url":"https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800&auto=format&fit=crop&q=80","alt":"Manga Panels Acrylic Wall Frame Image 5","order":4}]'::jsonb, '["Premium optical acrylic glass","Floating metal wall standoffs","UV-resistant print ink","Scratch-resistant backing"]'::jsonb, '["Sleek modern floating look","Vibrant black & white print contrast","Very easy to mount"]'::jsonb, '["Glossy screen attracts fingerprint smudges","Smaller size than expected"]'::jsonb, false, false, 2632, '2026-06-22T14:45:02.651Z', '2026-06-22T14:45:02.651Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000012', 'sunset-projection-lamp-v3', 'Sunset Projection Lamp v3', 'Project a warm sunset glow onto walls. Features a magnetic 360-degree rotating head, 16 color modes, and remote-controlled gradient speeds.', 'd10b7f8c-cbde-4e3a-b8ff-54a880f83d22', 'd31b7f8c-ccde-4e3a-b8ff-54a880f83d99', 760, 'AURA-HOME', '[{"url":"https://images.unsplash.com/photo-1513694203232-719a280e022f?w=600&auto=format&fit=crop&q=80","alt":"Sunset Projection Lamp v3 Image 1","order":0},{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Sunset Projection Lamp v3 Image 2","order":1},{"url":"https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=600&auto=format&fit=crop&q=80","alt":"Sunset Projection Lamp v3 Image 3","order":2},{"url":"https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800&auto=format&fit=crop&q=80","alt":"Sunset Projection Lamp v3 Image 4","order":3}]'::jsonb, '["16 RGB color modes","360-degree rotating dome head","USB power adaptor","Wireless remote control"]'::jsonb, '["Creates cozy vibes instantly","High quality optical glass dome","Magnetic head is fun to adjust"]'::jsonb, '["Requires being close to the wall for crisp circles","Short USB cable included"]'::jsonb, true, true, 11389, '2026-06-19T19:32:14.668Z', '2026-06-19T19:32:14.668Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000013', 'modular-pegboard-wall-organizer', 'Modular Pegboard Wall Organizer', 'Natural Birch wood pegboard with modular shelves, pegs, and containers. Customize your setup wall to store keyboards, controllers, or plants.', 'd10b7f8c-cbde-4e3a-b8ff-54a880f83d22', 'd10b7f8c-cbde-4e3a-b8ff-54a880f83d23', 1610, 'GRAIN & COLO', '[{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Modular Pegboard Wall Organizer Image 1","order":0},{"url":"https://images.unsplash.com/photo-1513694203232-719a280e022f?w=600&auto=format&fit=crop&q=80","alt":"Modular Pegboard Wall Organizer Image 2","order":1},{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Modular Pegboard Wall Organizer Image 3","order":2},{"url":"https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=600&auto=format&fit=crop&q=80","alt":"Modular Pegboard Wall Organizer Image 4","order":3},{"url":"https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800&auto=format&fit=crop&q=80","alt":"Modular Pegboard Wall Organizer Image 5","order":4}]'::jsonb, '["Nordic Birch plywood","4 modular shelves","8 wooden peg hooks","Includes heavy-duty wall anchors"]'::jsonb, '["Beautiful wooden grain aesthetic","Sturdy peg fittings","Endless configuration options"]'::jsonb, '["Installation requires drilling","Max load limit is 12kg"]'::jsonb, false, true, 4248, '2026-06-21T15:18:39.135Z', '2026-06-21T15:18:39.135Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000014', 'premium-faux-ivy-vine-strings-12-pack', 'Premium Faux Ivy Vine Strings (12-pack)', 'Add a soft touch of greenery to your bedroom. 12 strands of realistic silk ivy vines, perfect for hanging over curtains, LED lights, or bedframes.', 'd10b7f8c-cbde-4e3a-b8ff-54a880f83d22', 'd10b7f8c-cbde-4e3a-b8ff-54a880f83d24', 420, 'COZY-PLANTS', '[{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Premium Faux Ivy Vine Strings (12-pack) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1513694203232-719a280e022f?w=600&auto=format&fit=crop&q=80","alt":"Premium Faux Ivy Vine Strings (12-pack) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Premium Faux Ivy Vine Strings (12-pack) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=600&auto=format&fit=crop&q=80","alt":"Premium Faux Ivy Vine Strings (12-pack) Image 4","order":3},{"url":"https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800&auto=format&fit=crop&q=80","alt":"Premium Faux Ivy Vine Strings (12-pack) Image 5","order":4}]'::jsonb, '["Silk leaves with plastic stems","84 feet total length","High-fidelity texture printing","Comes with cable ties"]'::jsonb, '["Low cost room upgrade","Realistic leaf textures","No watering needed!"]'::jsonb, '["Initial plastic smell when unboxed","Leaves can fall off if handled roughly"]'::jsonb, false, true, 5187, '2026-06-22T01:39:53.751Z', '2026-06-22T01:39:53.751Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000015', 'oversized-heavy-iron-pump-cover', 'Oversized ''Heavy Iron'' Pump Cover', '320GSM heavy interlock cotton drop-shoulder tee. Designed to fit extra large to retain warmth at the start of workouts, and hold its boxy shape.', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e33', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e51', 1020, 'IRON-CRAFT', '[{"url":"https://images.unsplash.com/photo-1517838277536-f5f99be501cd?w=600&auto=format&fit=crop&q=80","alt":"Oversized ''Heavy Iron'' Pump Cover Image 1","order":0},{"url":"https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=600&auto=format&fit=crop&q=80","alt":"Oversized ''Heavy Iron'' Pump Cover Image 2","order":1},{"url":"https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=600&auto=format&fit=crop&q=80","alt":"Oversized ''Heavy Iron'' Pump Cover Image 3","order":2}]'::jsonb, '["320GSM Interlock Cotton","Acid washed charcoal","Durable double-stitched hem","Cracked-print graphic logo"]'::jsonb, '["Durable thick fabric","Flattering oversized drape","Excellent sweat absorption"]'::jsonb, '["Feels heavy in peak summer heat","Takes up space in gym bags"]'::jsonb, true, true, 6289, '2026-06-21T18:57:44.293Z', '2026-06-21T18:57:44.293Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000016', 'matte-black-stainless-shaker', 'Matte Black Stainless Shaker', 'Double-walled vacuum insulated shaker cup. Keeps pre-workouts ice cold for 12 hours. Zero leakage, odor-resistant steel interior.', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e33', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e52', 760, 'IRON-CRAFT', '[{"url":"https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=600&auto=format&fit=crop&q=80","alt":"Matte Black Stainless Shaker Image 1","order":0},{"url":"https://images.unsplash.com/photo-1517838277536-f5f99be501cd?w=600&auto=format&fit=crop&q=80","alt":"Matte Black Stainless Shaker Image 2","order":1},{"url":"https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=600&auto=format&fit=crop&q=80","alt":"Matte Black Stainless Shaker Image 3","order":2},{"url":"https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=600&auto=format&fit=crop&q=80","alt":"Matte Black Stainless Shaker Image 4","order":3}]'::jsonb, '["Double-wall vacuum insulation","Food-grade 304 Stainless steel","Leaking-proof flip cap","Embossed internal measurements"]'::jsonb, '["Keeps drinks cold forever","Zero plastic protein smell buildup","Satisfying snap lid closure"]'::jsonb, '["Not microwave or dishwasher safe","Outer paint can scratch against keys"]'::jsonb, false, true, 4378, '2026-06-20T05:36:15.742Z', '2026-06-20T05:36:15.742Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000017', 'heavyweight-boxy-hoodie-v2', 'Heavyweight Boxy Hoodie (V2)', '450GSM ultra-thick loopback cotton hoodie. Slightly cropped body with dropped shoulders and double-lined hood for the perfect slouchy silhouette.', 'c4c23f72-7cb6-49a3-a7a2-f674681643ab', 'd0b2f7a1-cb9e-4e4b-bbd8-4f81a8b1c1e0', 1710, 'AESTHETIX', '[{"url":"https://images.unsplash.com/photo-1543163521-1bf539c55dd2?w=600&auto=format&fit=crop&q=80","alt":"Heavyweight Boxy Hoodie (V2) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1620799140408-edc6dcb6d633?w=600&auto=format&fit=crop&q=80","alt":"Heavyweight Boxy Hoodie (V2) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1512436991641-6745cdb1723f?w=600&auto=format&fit=crop&q=80","alt":"Heavyweight Boxy Hoodie (V2) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1556911220-e15b29be8c8f?w=600&auto=format&fit=crop&q=80","alt":"Heavyweight Boxy Hoodie (V2) Image 4","order":3}]'::jsonb, '["450GSM Organic Cotton","Preshrunk vintage wash","No drawstring hood design","Ribbed side panels"]'::jsonb, '["Thick structured drape","Excellent warmth","Premium heavy feel"]'::jsonb, '["Slightly short fit for tall people","Takes longer to dry due to density"]'::jsonb, false, true, 4710, '2026-06-16T14:09:01.454Z', '2026-06-16T14:09:01.454Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000018', 'vintage-wash-utility-tee-v2', 'Vintage Wash Utility Tee (V2)', 'Relaxed fit 280GSM heavy tee featuring a distressed screenprint logo and double-stitched collar. Hand-faded charcoal dye makes each shirt unique.', 'c4c23f72-7cb6-49a3-a7a2-f674681643ab', 'c4c23f72-7cb6-49a3-a7a2-f674681643ac', 900, 'NO-SIGNAL', '[{"url":"https://images.unsplash.com/photo-1503342217505-b0a15ec3261c?w=600&auto=format&fit=crop&q=80","alt":"Vintage Wash Utility Tee (V2) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1583743814966-8936f5b7be1a?w=600&auto=format&fit=crop&q=80","alt":"Vintage Wash Utility Tee (V2) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1521572267360-ee0c2909d518?w=600&auto=format&fit=crop&q=80","alt":"Vintage Wash Utility Tee (V2) Image 3","order":2}]'::jsonb, '["280GSM Cotton","Distressed neck detailing","Pigment-dyed for vintage look","Eco-friendly screen-printing"]'::jsonb, '["Extremely soft feel","Durable thick collar","Unique custom wash color"]'::jsonb, '["Hand-wash recommended to keep print","Slight color run on first wash"]'::jsonb, false, false, 637, '2026-06-16T02:17:17.857Z', '2026-06-16T02:17:17.857Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000019', 'retro-runner-sneakers-v2-v2', 'Retro Runner Sneakers V2 (V2)', 'Crafted with suede overlays, open-cell mesh underlays, and a distressed pre-yellowed midsole for that retro 90s aesthetic.', 'c4c23f72-7cb6-49a3-a7a2-f674681643ab', 'a981fae8-cc4a-442a-a719-86f76c1251e0', 4500, 'HYPELAB', '[{"url":"https://images.unsplash.com/photo-1595950653106-6c9ebd614d3a?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 (V2) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1549298916-b41d501d3772?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 (V2) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1606107557195-0e29a4b5b4aa?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 (V2) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 (V2) Image 4","order":3}]'::jsonb, '["Premium calf suede","Breathable nylon mesh panels","EVA shock-absorbing sole","Reflective 3M safety piping"]'::jsonb, '["Extremely comfortable for walking","Perfect aesthetic retro shape","Breathable mesh"]'::jsonb, '["Suede gets ruined in the rain","Expensive price point"]'::jsonb, false, false, 2664, '2026-06-17T05:01:13.958Z', '2026-06-17T05:01:13.958Z'),
