  ('a3c8e42f-7c1a-47a2-bd32-000000000021', 'q1-pro-custom-keyboard-v2', 'Q1 Pro Custom Keyboard (V2)', '75% layout QMK/VIA wireless mechanical keyboard with full CNC aluminum body, double-gasket design, and hot-swappable switches.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'd881abf8-cdca-412a-a119-96f76c1262d0', 14850, 'Keychron', '[{"url":"https://images.unsplash.com/photo-1587829741301-dc798b83add3?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard (V2) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1626908013351-800ddd734b8a?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard (V2) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1618384887929-16ec33fab9ef?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard (V2) Image 3","order":2}]'::jsonb, '["Full CNC aluminum body","Wireless Bluetooth & 2.4G","Hot-swappable keys (3pin/5pin)","Screw-in PCB stabilizers"]'::jsonb, '["Immaculate heavy build quality","Satisfying deep ''thocky'' acoustic profile","Fully customizable keymap via VIA"]'::jsonb, '["Very heavy to carry around","High price barrier"]'::jsonb, false, false, 360, '2026-06-17T16:54:10.503Z', '2026-06-17T16:54:10.503Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000022', 'minimal-felt-desk-pad-medium-v2', 'Minimal Felt Desk Pad (Medium) (V2)', 'Made of 100% natural Merino wool felt with a non-slip cork base. Prevents desk scratches while adding acoustic dampening and a clean workspace texture.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'c51fa8b8-cffa-4f2a-8119-a6f76c1281e0', 1170, 'GRAIN & COLO', '[{"url":"https://images.unsplash.com/photo-1616440347437-b1c73416efc2?w=600&auto=format&fit=crop&q=80","alt":"Minimal Felt Desk Pad (Medium) (V2) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1632292224971-0d45778b3002?w=600&auto=format&fit=crop&q=80","alt":"Minimal Felt Desk Pad (Medium) (V2) Image 2","order":1}]'::jsonb, '["100% Merino Wool felt","4mm thickness","Eco-friendly non-slip cork backing","Stitched anti-fray borders"]'::jsonb, '["Very clean visual look","Dampens keyboard typing sounds","Comfortable skin contact"]'::jsonb, '["Wool is scratchy for sensitive skin","Cannot wash in washing machine"]'::jsonb, false, false, 1870, '2026-06-18T02:06:49.240Z', '2026-06-18T02:06:49.240Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000023', 'retro-rgb-led-monitor-lightbar-v2', 'Retro RGB LED Monitor Lightbar (V2)', 'Asymmetric screen lighting that eliminates glare. Features a smart wireless dial to control brightness and color temperature on the fly.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3d', 2250, 'LUMEX', '[{"url":"https://images.unsplash.com/photo-1563089145-599997674d42?w=600&auto=format&fit=crop&q=80","alt":"Retro RGB LED Monitor Lightbar (V2) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1550745165-9bc0b252726f?w=600&auto=format&fit=crop&q=80","alt":"Retro RGB LED Monitor Lightbar (V2) Image 2","order":1}]'::jsonb, '["Asymmetric optical design","USB-C powered","Wireless desktop controller dial","Backlight ambient RGB projector"]'::jsonb, '["Saves desk space","No direct light shines on screen","Wireless dial is very smooth"]'::jsonb, '["Struggles to fit on curved monitors","Dial batteries need replacement yearly"]'::jsonb, false, false, 1232, '2026-06-17T17:03:24.997Z', '2026-06-17T17:03:24.997Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000024', 'studio-sound-pro-headphones-v2', 'Studio Sound Pro Headphones (V2)', 'Closed-back studio monitoring headphones with flat response curves, 45mm drivers, and plush memory foam earcups for long audio editing sessions.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3c', 10790, 'AUDIO-TECH', '[{"url":"https://images.unsplash.com/photo-1546435770-a3e426bf472b?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones (V2) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1484704849700-f032a568e944?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones (V2) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones (V2) Image 3","order":2}]'::jsonb, '["45mm large-aperture drivers","90-degree swiveling earcups","Detachable cables included","Plush memory foam pads"]'::jsonb, '["Accurate, non-colored sound profile","Comfortable head clamping pressure","Foldable travel design"]'::jsonb, '["Sound is analytical (not bass-boosted)","Plastic build feels slightly squeaky"]'::jsonb, false, false, 2231, '2026-06-18T02:17:27.654Z', '2026-06-18T02:17:27.654Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000025', 'neo-tokyo-cyberpunk-bomber-jacket-v2', 'Neo-Tokyo Cyberpunk Bomber Jacket (V2)', 'Sleek water-resistant bomber featuring kanji embroidery, neon interior lining, and heavy-duty utility clips. Cyberpunk vibes for street fashion.', 'e10a6e3d-0453-4bf8-b98a-54c330f81d11', 'e10a6e3d-0453-4bf8-b98a-54c330f81d12', 3150, 'TOKYO-DRIP', '[{"url":"https://images.unsplash.com/photo-1521572267360-ee0c2909d518?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V2) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1503342217505-b0a15ec3261c?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V2) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1583743814966-8936f5b7be1a?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V2) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1543163521-1bf539c55dd2?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V2) Image 4","order":3}]'::jsonb, '["Nylon outer shell","Embroidered back kanji","Dual utility metal clip straps","Insulated neon orange lining"]'::jsonb, '["Water-resistant utility outer","Bold premium embroidery","Inside zip pockets"]'::jsonb, '["Quite warm, not suitable for hot summers","Embroidery needs care while washing"]'::jsonb, false, true, 6160, '2026-06-17T16:56:29.331Z', '2026-06-17T16:56:29.331Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000026', 'limited-edition-mecha-action-figure-v2', 'Limited Edition Mecha Action Figure (V2)', 'Highly articulated 1/144 scale metal composite action figure. Incredible paint detail, customizable weapon loadouts, and a custom display stand.', 'e10a6e3d-0453-4bf8-b98a-54c330f81d11', 'e18d6e3f-0463-4bf8-b98a-54d330f81c99', 8100, 'BANDAI', '[{"url":"https://images.unsplash.com/photo-1534447677768-be436bb09401?w=600&auto=format&fit=crop&q=80","alt":"Limited Edition Mecha Action Figure (V2) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1607604276583-eef5d076aa5f?w=600&auto=format&fit=crop&q=80","alt":"Limited Edition Mecha Action Figure (V2) Image 2","order":1}]'::jsonb, '["Diecast metal and ABS build","1/144 custom scale","20+ articulation joints","LED eye illumination"]'::jsonb, '["Metal joints ensure solid posing","Incredible museum-grade paintwork","Exquisite collectors packaging"]'::jsonb, '["Very small delicate parts","Fragile antennas"]'::jsonb, false, true, 5757, '2026-06-17T04:21:25.842Z', '2026-06-17T04:21:25.842Z'),
