  ('a3c8e42f-7c1a-47a2-bd32-000000000028', 'sunset-projection-lamp-v3-v2', 'Sunset Projection Lamp v3 (V2)', 'Project a warm sunset glow onto walls. Features a magnetic 360-degree rotating head, 16 color modes, and remote-controlled gradient speeds.', 'd10b7f8c-cbde-4e3a-b8ff-54a880f83d22', 'd31b7f8c-ccde-4e3a-b8ff-54a880f83d99', 810, 'AURA-HOME', '[{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Sunset Projection Lamp v3 (V2) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=600&auto=format&fit=crop&q=80","alt":"Sunset Projection Lamp v3 (V2) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800&auto=format&fit=crop&q=80","alt":"Sunset Projection Lamp v3 (V2) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1513694203232-719a280e022f?w=600&auto=format&fit=crop&q=80","alt":"Sunset Projection Lamp v3 (V2) Image 4","order":3}]'::jsonb, '["16 RGB color modes","360-degree rotating dome head","USB power adaptor","Wireless remote control"]'::jsonb, '["Creates cozy vibes instantly","High quality optical glass dome","Magnetic head is fun to adjust"]'::jsonb, '["Requires being close to the wall for crisp circles","Short USB cable included"]'::jsonb, false, false, 2710, '2026-06-16T12:00:20.942Z', '2026-06-16T12:00:20.942Z'),
