  ('a3c8e42f-7c1a-47a2-bd32-000000000037', 'q1-pro-custom-keyboard-v3', 'Q1 Pro Custom Keyboard (V3)', '75% layout QMK/VIA wireless mechanical keyboard with full CNC aluminum body, double-gasket design, and hot-swappable switches.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'd881abf8-cdca-412a-a119-96f76c1262d0', 15670, 'Keychron', '[{"url":"https://images.unsplash.com/photo-1626908013351-800ddd734b8a?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard (V3) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1618384887929-16ec33fab9ef?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard (V3) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1587829741301-dc798b83add3?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard (V3) Image 3","order":2}]'::jsonb, '["Full CNC aluminum body","Wireless Bluetooth & 2.4G","Hot-swappable keys (3pin/5pin)","Screw-in PCB stabilizers"]'::jsonb, '["Immaculate heavy build quality","Satisfying deep ''thocky'' acoustic profile","Fully customizable keymap via VIA"]'::jsonb, '["Very heavy to carry around","High price barrier"]'::jsonb, false, true, 7321, '2026-06-12T13:33:05.516Z', '2026-06-12T13:33:05.516Z'),
