  ('a3c8e42f-7c1a-47a2-bd32-000000000039', 'retro-rgb-led-monitor-lightbar-v3', 'Retro RGB LED Monitor Lightbar (V3)', 'Asymmetric screen lighting that eliminates glare. Features a smart wireless dial to control brightness and color temperature on the fly.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3d', 2370, 'LUMEX', '[{"url":"https://images.unsplash.com/photo-1550745165-9bc0b252726f?w=600&auto=format&fit=crop&q=80","alt":"Retro RGB LED Monitor Lightbar (V3) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1563089145-599997674d42?w=600&auto=format&fit=crop&q=80","alt":"Retro RGB LED Monitor Lightbar (V3) Image 2","order":1}]'::jsonb, '["Asymmetric optical design","USB-C powered","Wireless desktop controller dial","Backlight ambient RGB projector"]'::jsonb, '["Saves desk space","No direct light shines on screen","Wireless dial is very smooth"]'::jsonb, '["Struggles to fit on curved monitors","Dial batteries need replacement yearly"]'::jsonb, false, true, 6550, '2026-06-11T18:00:35.417Z', '2026-06-11T18:00:35.417Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000040', 'studio-sound-pro-headphones-v3', 'Studio Sound Pro Headphones (V3)', 'Closed-back studio monitoring headphones with flat response curves, 45mm drivers, and plush memory foam earcups for long audio editing sessions.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3c', 11390, 'AUDIO-TECH', '[{"url":"https://images.unsplash.com/photo-1484704849700-f032a568e944?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones (V3) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones (V3) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1546435770-a3e426bf472b?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones (V3) Image 3","order":2}]'::jsonb, '["45mm large-aperture drivers","90-degree swiveling earcups","Detachable cables included","Plush memory foam pads"]'::jsonb, '["Accurate, non-colored sound profile","Comfortable head clamping pressure","Foldable travel design"]'::jsonb, '["Sound is analytical (not bass-boosted)","Plastic build feels slightly squeaky"]'::jsonb, false, false, 1868, '2026-06-12T09:25:53.074Z', '2026-06-12T09:25:53.074Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000041', 'neo-tokyo-cyberpunk-bomber-jacket-v3', 'Neo-Tokyo Cyberpunk Bomber Jacket (V3)', 'Sleek water-resistant bomber featuring kanji embroidery, neon interior lining, and heavy-duty utility clips. Cyberpunk vibes for street fashion.', 'e10a6e3d-0453-4bf8-b98a-54c330f81d11', 'e10a6e3d-0453-4bf8-b98a-54c330f81d12', 3320, 'TOKYO-DRIP', '[{"url":"https://images.unsplash.com/photo-1503342217505-b0a15ec3261c?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V3) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1583743814966-8936f5b7be1a?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V3) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1543163521-1bf539c55dd2?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V3) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1521572267360-ee0c2909d518?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V3) Image 4","order":3}]'::jsonb, '["Nylon outer shell","Embroidered back kanji","Dual utility metal clip straps","Insulated neon orange lining"]'::jsonb, '["Water-resistant utility outer","Bold premium embroidery","Inside zip pockets"]'::jsonb, '["Quite warm, not suitable for hot summers","Embroidery needs care while washing"]'::jsonb, false, true, 8499, '2026-06-13T06:10:36.697Z', '2026-06-13T06:10:36.697Z'),
