  ('a3c8e42f-7c1a-47a2-bd32-000000000050', 'vintage-wash-utility-tee-v4', 'Vintage Wash Utility Tee (V4)', 'Relaxed fit 280GSM heavy tee featuring a distressed screenprint logo and double-stitched collar. Hand-faded charcoal dye makes each shirt unique.', 'c4c23f72-7cb6-49a3-a7a2-f674681643ab', 'c4c23f72-7cb6-49a3-a7a2-f674681643ac', 1000, 'NO-SIGNAL', '[{"url":"https://images.unsplash.com/photo-1521572267360-ee0c2909d518?w=600&auto=format&fit=crop&q=80","alt":"Vintage Wash Utility Tee (V4) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1503342217505-b0a15ec3261c?w=600&auto=format&fit=crop&q=80","alt":"Vintage Wash Utility Tee (V4) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1583743814966-8936f5b7be1a?w=600&auto=format&fit=crop&q=80","alt":"Vintage Wash Utility Tee (V4) Image 3","order":2}]'::jsonb, '["280GSM Cotton","Distressed neck detailing","Pigment-dyed for vintage look","Eco-friendly screen-printing"]'::jsonb, '["Extremely soft feel","Durable thick collar","Unique custom wash color"]'::jsonb, '["Hand-wash recommended to keep print","Slight color run on first wash"]'::jsonb, false, true, 5474, '2026-06-08T16:42:05.492Z', '2026-06-08T16:42:05.492Z'),
