  ('a3c8e42f-7c1a-47a2-bd32-000000000063', 'oversized-heavy-iron-pump-cover-v4', 'Oversized ''Heavy Iron'' Pump Cover (V4)', '320GSM heavy interlock cotton drop-shoulder tee. Designed to fit extra large to retain warmth at the start of workouts, and hold its boxy shape.', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e33', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e51', 1200, 'IRON-CRAFT', '[{"url":"https://images.unsplash.com/photo-1517838277536-f5f99be501cd?w=600&auto=format&fit=crop&q=80","alt":"Oversized ''Heavy Iron'' Pump Cover (V4) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=600&auto=format&fit=crop&q=80","alt":"Oversized ''Heavy Iron'' Pump Cover (V4) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=600&auto=format&fit=crop&q=80","alt":"Oversized ''Heavy Iron'' Pump Cover (V4) Image 3","order":2}]'::jsonb, '["320GSM Interlock Cotton","Acid washed charcoal","Durable double-stitched hem","Cracked-print graphic logo"]'::jsonb, '["Durable thick fabric","Flattering oversized drape","Excellent sweat absorption"]'::jsonb, '["Feels heavy in peak summer heat","Takes up space in gym bags"]'::jsonb, false, true, 3131, '2026-06-07T21:40:00.727Z', '2026-06-07T21:40:00.727Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000064', 'matte-black-stainless-shaker-v4', 'Matte Black Stainless Shaker (V4)', 'Double-walled vacuum insulated shaker cup. Keeps pre-workouts ice cold for 12 hours. Zero leakage, odor-resistant steel interior.', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e33', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e52', 900, 'IRON-CRAFT', '[{"url":"https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=600&auto=format&fit=crop&q=80","alt":"Matte Black Stainless Shaker (V4) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=600&auto=format&fit=crop&q=80","alt":"Matte Black Stainless Shaker (V4) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1517838277536-f5f99be501cd?w=600&auto=format&fit=crop&q=80","alt":"Matte Black Stainless Shaker (V4) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=600&auto=format&fit=crop&q=80","alt":"Matte Black Stainless Shaker (V4) Image 4","order":3}]'::jsonb, '["Double-wall vacuum insulation","Food-grade 304 Stainless steel","Leaking-proof flip cap","Embossed internal measurements"]'::jsonb, '["Keeps drinks cold forever","Zero plastic protein smell buildup","Satisfying snap lid closure"]'::jsonb, '["Not microwave or dishwasher safe","Outer paint can scratch against keys"]'::jsonb, false, false, 2546, '2026-06-09T19:12:51.049Z', '2026-06-09T19:12:51.049Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000065', 'heavyweight-boxy-hoodie-v5', 'Heavyweight Boxy Hoodie (V5)', '450GSM ultra-thick loopback cotton hoodie. Slightly cropped body with dropped shoulders and double-lined hood for the perfect slouchy silhouette.', 'c4c23f72-7cb6-49a3-a7a2-f674681643ab', 'd0b2f7a1-cb9e-4e4b-bbd8-4f81a8b1c1e0', 1990, 'AESTHETIX', '[{"url":"https://images.unsplash.com/photo-1556911220-e15b29be8c8f?w=600&auto=format&fit=crop&q=80","alt":"Heavyweight Boxy Hoodie (V5) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1543163521-1bf539c55dd2?w=600&auto=format&fit=crop&q=80","alt":"Heavyweight Boxy Hoodie (V5) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1620799140408-edc6dcb6d633?w=600&auto=format&fit=crop&q=80","alt":"Heavyweight Boxy Hoodie (V5) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1512436991641-6745cdb1723f?w=600&auto=format&fit=crop&q=80","alt":"Heavyweight Boxy Hoodie (V5) Image 4","order":3}]'::jsonb, '["450GSM Organic Cotton","Preshrunk vintage wash","No drawstring hood design","Ribbed side panels"]'::jsonb, '["Thick structured drape","Excellent warmth","Premium heavy feel"]'::jsonb, '["Slightly short fit for tall people","Takes longer to dry due to density"]'::jsonb, false, true, 6063, '2026-06-04T02:52:24.799Z', '2026-06-04T02:52:24.799Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000066', 'vintage-wash-utility-tee-v5', 'Vintage Wash Utility Tee (V5)', 'Relaxed fit 280GSM heavy tee featuring a distressed screenprint logo and double-stitched collar. Hand-faded charcoal dye makes each shirt unique.', 'c4c23f72-7cb6-49a3-a7a2-f674681643ab', 'c4c23f72-7cb6-49a3-a7a2-f674681643ac', 1050, 'NO-SIGNAL', '[{"url":"https://images.unsplash.com/photo-1503342217505-b0a15ec3261c?w=600&auto=format&fit=crop&q=80","alt":"Vintage Wash Utility Tee (V5) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1583743814966-8936f5b7be1a?w=600&auto=format&fit=crop&q=80","alt":"Vintage Wash Utility Tee (V5) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1521572267360-ee0c2909d518?w=600&auto=format&fit=crop&q=80","alt":"Vintage Wash Utility Tee (V5) Image 3","order":2}]'::jsonb, '["280GSM Cotton","Distressed neck detailing","Pigment-dyed for vintage look","Eco-friendly screen-printing"]'::jsonb, '["Extremely soft feel","Durable thick collar","Unique custom wash color"]'::jsonb, '["Hand-wash recommended to keep print","Slight color run on first wash"]'::jsonb, false, true, 4567, '2026-06-05T09:03:48.169Z', '2026-06-05T09:03:48.169Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000067', 'retro-runner-sneakers-v2-v5', 'Retro Runner Sneakers V2 (V5)', 'Crafted with suede overlays, open-cell mesh underlays, and a distressed pre-yellowed midsole for that retro 90s aesthetic.', 'c4c23f72-7cb6-49a3-a7a2-f674681643ab', 'a981fae8-cc4a-442a-a719-86f76c1251e0', 5250, 'HYPELAB', '[{"url":"https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 (V5) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1595950653106-6c9ebd614d3a?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 (V5) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1549298916-b41d501d3772?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 (V5) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1606107557195-0e29a4b5b4aa?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 (V5) Image 4","order":3}]'::jsonb, '["Premium calf suede","Breathable nylon mesh panels","EVA shock-absorbing sole","Reflective 3M safety piping"]'::jsonb, '["Extremely comfortable for walking","Perfect aesthetic retro shape","Breathable mesh"]'::jsonb, '["Suede gets ruined in the rain","Expensive price point"]'::jsonb, false, false, 1413, '2026-06-05T11:07:35.614Z', '2026-06-05T11:07:35.614Z'),
