  ('a3c8e42f-7c1a-47a2-bd32-000000000083', 'retro-runner-sneakers-v2-v6', 'Retro Runner Sneakers V2 (V6)', 'Crafted with suede overlays, open-cell mesh underlays, and a distressed pre-yellowed midsole for that retro 90s aesthetic.', 'c4c23f72-7cb6-49a3-a7a2-f674681643ab', 'a981fae8-cc4a-442a-a719-86f76c1251e0', 5500, 'HYPELAB', '[{"url":"https://images.unsplash.com/photo-1595950653106-6c9ebd614d3a?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 (V6) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1549298916-b41d501d3772?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 (V6) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1606107557195-0e29a4b5b4aa?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 (V6) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=600&auto=format&fit=crop&q=80","alt":"Retro Runner Sneakers V2 (V6) Image 4","order":3}]'::jsonb, '["Premium calf suede","Breathable nylon mesh panels","EVA shock-absorbing sole","Reflective 3M safety piping"]'::jsonb, '["Extremely comfortable for walking","Perfect aesthetic retro shape","Breathable mesh"]'::jsonb, '["Suede gets ruined in the rain","Expensive price point"]'::jsonb, false, true, 3320, '2026-06-01T13:07:44.149Z', '2026-06-01T13:07:44.149Z'),
