  ('a3c8e42f-7c1a-47a2-bd32-000000000085', 'q1-pro-custom-keyboard-v6', 'Q1 Pro Custom Keyboard (V6)', '75% layout QMK/VIA wireless mechanical keyboard with full CNC aluminum body, double-gasket design, and hot-swappable switches.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'd881abf8-cdca-412a-a119-96f76c1262d0', 18150, 'Keychron', '[{"url":"https://images.unsplash.com/photo-1626908013351-800ddd734b8a?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard (V6) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1618384887929-16ec33fab9ef?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard (V6) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1587829741301-dc798b83add3?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard (V6) Image 3","order":2}]'::jsonb, '["Full CNC aluminum body","Wireless Bluetooth & 2.4G","Hot-swappable keys (3pin/5pin)","Screw-in PCB stabilizers"]'::jsonb, '["Immaculate heavy build quality","Satisfying deep ''thocky'' acoustic profile","Fully customizable keymap via VIA"]'::jsonb, '["Very heavy to carry around","High price barrier"]'::jsonb, false, true, 4384, '2026-06-01T20:19:03.351Z', '2026-06-01T20:19:03.351Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000086', 'minimal-felt-desk-pad-medium-v6', 'Minimal Felt Desk Pad (Medium) (V6)', 'Made of 100% natural Merino wool felt with a non-slip cork base. Prevents desk scratches while adding acoustic dampening and a clean workspace texture.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'c51fa8b8-cffa-4f2a-8119-a6f76c1281e0', 1430, 'GRAIN & COLO', '[{"url":"https://images.unsplash.com/photo-1616440347437-b1c73416efc2?w=600&auto=format&fit=crop&q=80","alt":"Minimal Felt Desk Pad (Medium) (V6) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1632292224971-0d45778b3002?w=600&auto=format&fit=crop&q=80","alt":"Minimal Felt Desk Pad (Medium) (V6) Image 2","order":1}]'::jsonb, '["100% Merino Wool felt","4mm thickness","Eco-friendly non-slip cork backing","Stitched anti-fray borders"]'::jsonb, '["Very clean visual look","Dampens keyboard typing sounds","Comfortable skin contact"]'::jsonb, '["Wool is scratchy for sensitive skin","Cannot wash in washing machine"]'::jsonb, false, true, 6979, '2026-06-02T03:55:32.581Z', '2026-06-02T03:55:32.581Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000087', 'retro-rgb-led-monitor-lightbar-v6', 'Retro RGB LED Monitor Lightbar (V6)', 'Asymmetric screen lighting that eliminates glare. Features a smart wireless dial to control brightness and color temperature on the fly.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3d', 2750, 'LUMEX', '[{"url":"https://images.unsplash.com/photo-1563089145-599997674d42?w=600&auto=format&fit=crop&q=80","alt":"Retro RGB LED Monitor Lightbar (V6) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1550745165-9bc0b252726f?w=600&auto=format&fit=crop&q=80","alt":"Retro RGB LED Monitor Lightbar (V6) Image 2","order":1}]'::jsonb, '["Asymmetric optical design","USB-C powered","Wireless desktop controller dial","Backlight ambient RGB projector"]'::jsonb, '["Saves desk space","No direct light shines on screen","Wireless dial is very smooth"]'::jsonb, '["Struggles to fit on curved monitors","Dial batteries need replacement yearly"]'::jsonb, false, true, 8374, '2026-05-31T15:38:07.148Z', '2026-05-31T15:38:07.148Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000088', 'studio-sound-pro-headphones-v6', 'Studio Sound Pro Headphones (V6)', 'Closed-back studio monitoring headphones with flat response curves, 45mm drivers, and plush memory foam earcups for long audio editing sessions.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3c', 13190, 'AUDIO-TECH', '[{"url":"https://images.unsplash.com/photo-1484704849700-f032a568e944?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones (V6) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones (V6) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1546435770-a3e426bf472b?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones (V6) Image 3","order":2}]'::jsonb, '["45mm large-aperture drivers","90-degree swiveling earcups","Detachable cables included","Plush memory foam pads"]'::jsonb, '["Accurate, non-colored sound profile","Comfortable head clamping pressure","Foldable travel design"]'::jsonb, '["Sound is analytical (not bass-boosted)","Plastic build feels slightly squeaky"]'::jsonb, false, true, 3325, '2026-05-31T01:21:18.566Z', '2026-05-31T01:21:18.566Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000089', 'neo-tokyo-cyberpunk-bomber-jacket-v6', 'Neo-Tokyo Cyberpunk Bomber Jacket (V6)', 'Sleek water-resistant bomber featuring kanji embroidery, neon interior lining, and heavy-duty utility clips. Cyberpunk vibes for street fashion.', 'e10a6e3d-0453-4bf8-b98a-54c330f81d11', 'e10a6e3d-0453-4bf8-b98a-54c330f81d12', 3850, 'TOKYO-DRIP', '[{"url":"https://images.unsplash.com/photo-1521572267360-ee0c2909d518?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V6) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1503342217505-b0a15ec3261c?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V6) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1583743814966-8936f5b7be1a?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V6) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1543163521-1bf539c55dd2?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V6) Image 4","order":3}]'::jsonb, '["Nylon outer shell","Embroidered back kanji","Dual utility metal clip straps","Insulated neon orange lining"]'::jsonb, '["Water-resistant utility outer","Bold premium embroidery","Inside zip pockets"]'::jsonb, '["Quite warm, not suitable for hot summers","Embroidery needs care while washing"]'::jsonb, false, true, 5867, '2026-05-31T13:18:57.549Z', '2026-05-31T13:18:57.549Z'),
