  ('a3c8e42f-7c1a-47a2-bd32-000000000095', 'oversized-heavy-iron-pump-cover-v6', 'Oversized ''Heavy Iron'' Pump Cover (V6)', '320GSM heavy interlock cotton drop-shoulder tee. Designed to fit extra large to retain warmth at the start of workouts, and hold its boxy shape.', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e33', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e51', 1320, 'IRON-CRAFT', '[{"url":"https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=600&auto=format&fit=crop&q=80","alt":"Oversized ''Heavy Iron'' Pump Cover (V6) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1517838277536-f5f99be501cd?w=600&auto=format&fit=crop&q=80","alt":"Oversized ''Heavy Iron'' Pump Cover (V6) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=600&auto=format&fit=crop&q=80","alt":"Oversized ''Heavy Iron'' Pump Cover (V6) Image 3","order":2}]'::jsonb, '["320GSM Interlock Cotton","Acid washed charcoal","Durable double-stitched hem","Cracked-print graphic logo"]'::jsonb, '["Durable thick fabric","Flattering oversized drape","Excellent sweat absorption"]'::jsonb, '["Feels heavy in peak summer heat","Takes up space in gym bags"]'::jsonb, false, false, 862, '2026-06-01T04:40:17.910Z', '2026-06-01T04:40:17.910Z'),
