  ('a3c8e42f-7c1a-47a2-bd32-000000000101', 'q1-pro-custom-keyboard-v7', 'Q1 Pro Custom Keyboard (V7)', '75% layout QMK/VIA wireless mechanical keyboard with full CNC aluminum body, double-gasket design, and hot-swappable switches.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'd881abf8-cdca-412a-a119-96f76c1262d0', 18970, 'Keychron', '[{"url":"https://images.unsplash.com/photo-1618384887929-16ec33fab9ef?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard (V7) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1587829741301-dc798b83add3?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard (V7) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1626908013351-800ddd734b8a?w=600&auto=format&fit=crop&q=80","alt":"Q1 Pro Custom Keyboard (V7) Image 3","order":2}]'::jsonb, '["Full CNC aluminum body","Wireless Bluetooth & 2.4G","Hot-swappable keys (3pin/5pin)","Screw-in PCB stabilizers"]'::jsonb, '["Immaculate heavy build quality","Satisfying deep ''thocky'' acoustic profile","Fully customizable keymap via VIA"]'::jsonb, '["Very heavy to carry around","High price barrier"]'::jsonb, false, true, 6534, '2026-05-27T10:01:16.783Z', '2026-05-27T10:01:16.783Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000102', 'minimal-felt-desk-pad-medium-v7', 'Minimal Felt Desk Pad (Medium) (V7)', 'Made of 100% natural Merino wool felt with a non-slip cork base. Prevents desk scratches while adding acoustic dampening and a clean workspace texture.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'c51fa8b8-cffa-4f2a-8119-a6f76c1281e0', 1490, 'GRAIN & COLO', '[{"url":"https://images.unsplash.com/photo-1632292224971-0d45778b3002?w=600&auto=format&fit=crop&q=80","alt":"Minimal Felt Desk Pad (Medium) (V7) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1616440347437-b1c73416efc2?w=600&auto=format&fit=crop&q=80","alt":"Minimal Felt Desk Pad (Medium) (V7) Image 2","order":1}]'::jsonb, '["100% Merino Wool felt","4mm thickness","Eco-friendly non-slip cork backing","Stitched anti-fray borders"]'::jsonb, '["Very clean visual look","Dampens keyboard typing sounds","Comfortable skin contact"]'::jsonb, '["Wool is scratchy for sensitive skin","Cannot wash in washing machine"]'::jsonb, false, false, 2867, '2026-05-28T01:43:40.322Z', '2026-05-28T01:43:40.322Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000103', 'retro-rgb-led-monitor-lightbar-v7', 'Retro RGB LED Monitor Lightbar (V7)', 'Asymmetric screen lighting that eliminates glare. Features a smart wireless dial to control brightness and color temperature on the fly.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3d', 2870, 'LUMEX', '[{"url":"https://images.unsplash.com/photo-1550745165-9bc0b252726f?w=600&auto=format&fit=crop&q=80","alt":"Retro RGB LED Monitor Lightbar (V7) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1563089145-599997674d42?w=600&auto=format&fit=crop&q=80","alt":"Retro RGB LED Monitor Lightbar (V7) Image 2","order":1}]'::jsonb, '["Asymmetric optical design","USB-C powered","Wireless desktop controller dial","Backlight ambient RGB projector"]'::jsonb, '["Saves desk space","No direct light shines on screen","Wireless dial is very smooth"]'::jsonb, '["Struggles to fit on curved monitors","Dial batteries need replacement yearly"]'::jsonb, false, true, 8751, '2026-05-27T23:48:28.466Z', '2026-05-27T23:48:28.466Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000104', 'studio-sound-pro-headphones-v7', 'Studio Sound Pro Headphones (V7)', 'Closed-back studio monitoring headphones with flat response curves, 45mm drivers, and plush memory foam earcups for long audio editing sessions.', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3b', 'b09d0e2e-bfba-40a1-8d2a-a9cb84f67c3c', 13790, 'AUDIO-TECH', '[{"url":"https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones (V7) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1546435770-a3e426bf472b?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones (V7) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1484704849700-f032a568e944?w=600&auto=format&fit=crop&q=80","alt":"Studio Sound Pro Headphones (V7) Image 3","order":2}]'::jsonb, '["45mm large-aperture drivers","90-degree swiveling earcups","Detachable cables included","Plush memory foam pads"]'::jsonb, '["Accurate, non-colored sound profile","Comfortable head clamping pressure","Foldable travel design"]'::jsonb, '["Sound is analytical (not bass-boosted)","Plastic build feels slightly squeaky"]'::jsonb, false, true, 4591, '2026-05-27T01:50:52.871Z', '2026-05-27T01:50:52.871Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000105', 'neo-tokyo-cyberpunk-bomber-jacket-v7', 'Neo-Tokyo Cyberpunk Bomber Jacket (V7)', 'Sleek water-resistant bomber featuring kanji embroidery, neon interior lining, and heavy-duty utility clips. Cyberpunk vibes for street fashion.', 'e10a6e3d-0453-4bf8-b98a-54c330f81d11', 'e10a6e3d-0453-4bf8-b98a-54c330f81d12', 4020, 'TOKYO-DRIP', '[{"url":"https://images.unsplash.com/photo-1503342217505-b0a15ec3261c?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V7) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1583743814966-8936f5b7be1a?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V7) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1543163521-1bf539c55dd2?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V7) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1521572267360-ee0c2909d518?w=600&auto=format&fit=crop&q=80","alt":"Neo-Tokyo Cyberpunk Bomber Jacket (V7) Image 4","order":3}]'::jsonb, '["Nylon outer shell","Embroidered back kanji","Dual utility metal clip straps","Insulated neon orange lining"]'::jsonb, '["Water-resistant utility outer","Bold premium embroidery","Inside zip pockets"]'::jsonb, '["Quite warm, not suitable for hot summers","Embroidery needs care while washing"]'::jsonb, false, true, 4959, '2026-05-26T18:03:09.303Z', '2026-05-26T18:03:09.303Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000106', 'limited-edition-mecha-action-figure-v7', 'Limited Edition Mecha Action Figure (V7)', 'Highly articulated 1/144 scale metal composite action figure. Incredible paint detail, customizable weapon loadouts, and a custom display stand.', 'e10a6e3d-0453-4bf8-b98a-54c330f81d11', 'e18d6e3f-0463-4bf8-b98a-54d330f81c99', 10350, 'BANDAI', '[{"url":"https://images.unsplash.com/photo-1607604276583-eef5d076aa5f?w=600&auto=format&fit=crop&q=80","alt":"Limited Edition Mecha Action Figure (V7) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1534447677768-be436bb09401?w=600&auto=format&fit=crop&q=80","alt":"Limited Edition Mecha Action Figure (V7) Image 2","order":1}]'::jsonb, '["Diecast metal and ABS build","1/144 custom scale","20+ articulation joints","LED eye illumination"]'::jsonb, '["Metal joints ensure solid posing","Incredible museum-grade paintwork","Exquisite collectors packaging"]'::jsonb, '["Very small delicate parts","Fragile antennas"]'::jsonb, false, true, 5429, '2026-05-28T12:50:31.607Z', '2026-05-28T12:50:31.607Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000107', 'manga-panels-acrylic-wall-frame-v7', 'Manga Panels Acrylic Wall Frame (V7)', 'High-resolution printed acrylic glass displaying classic retro manga pages. Double-layered float design for a sleek 3D shadow effect.', 'e10a6e3d-0453-4bf8-b98a-54c330f81d11', 'e10a6e3d-0453-4bf8-b98a-54c330f81d13', 920, 'TOKYO-DRIP', '[{"url":"https://images.unsplash.com/photo-1513694203232-719a280e022f?w=600&auto=format&fit=crop&q=80","alt":"Manga Panels Acrylic Wall Frame (V7) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Manga Panels Acrylic Wall Frame (V7) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=600&auto=format&fit=crop&q=80","alt":"Manga Panels Acrylic Wall Frame (V7) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800&auto=format&fit=crop&q=80","alt":"Manga Panels Acrylic Wall Frame (V7) Image 4","order":3},{"url":"https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800&auto=format&fit=crop&q=80","alt":"Manga Panels Acrylic Wall Frame (V7) Image 5","order":4}]'::jsonb, '["Premium optical acrylic glass","Floating metal wall standoffs","UV-resistant print ink","Scratch-resistant backing"]'::jsonb, '["Sleek modern floating look","Vibrant black & white print contrast","Very easy to mount"]'::jsonb, '["Glossy screen attracts fingerprint smudges","Smaller size than expected"]'::jsonb, false, false, 2909, '2026-05-28T12:43:35.825Z', '2026-05-28T12:43:35.825Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000108', 'sunset-projection-lamp-v3-v7', 'Sunset Projection Lamp v3 (V7)', 'Project a warm sunset glow onto walls. Features a magnetic 360-degree rotating head, 16 color modes, and remote-controlled gradient speeds.', 'd10b7f8c-cbde-4e3a-b8ff-54a880f83d22', 'd31b7f8c-ccde-4e3a-b8ff-54a880f83d99', 1030, 'AURA-HOME', '[{"url":"https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=600&auto=format&fit=crop&q=80","alt":"Sunset Projection Lamp v3 (V7) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800&auto=format&fit=crop&q=80","alt":"Sunset Projection Lamp v3 (V7) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1513694203232-719a280e022f?w=600&auto=format&fit=crop&q=80","alt":"Sunset Projection Lamp v3 (V7) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Sunset Projection Lamp v3 (V7) Image 4","order":3}]'::jsonb, '["16 RGB color modes","360-degree rotating dome head","USB power adaptor","Wireless remote control"]'::jsonb, '["Creates cozy vibes instantly","High quality optical glass dome","Magnetic head is fun to adjust"]'::jsonb, '["Requires being close to the wall for crisp circles","Short USB cable included"]'::jsonb, false, true, 7168, '2026-05-26T21:32:23.999Z', '2026-05-26T21:32:23.999Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000109', 'modular-pegboard-wall-organizer-v7', 'Modular Pegboard Wall Organizer (V7)', 'Natural Birch wood pegboard with modular shelves, pegs, and containers. Customize your setup wall to store keyboards, controllers, or plants.', 'd10b7f8c-cbde-4e3a-b8ff-54a880f83d22', 'd10b7f8c-cbde-4e3a-b8ff-54a880f83d23', 2180, 'GRAIN & COLO', '[{"url":"https://images.unsplash.com/photo-1513694203232-719a280e022f?w=600&auto=format&fit=crop&q=80","alt":"Modular Pegboard Wall Organizer (V7) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Modular Pegboard Wall Organizer (V7) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=600&auto=format&fit=crop&q=80","alt":"Modular Pegboard Wall Organizer (V7) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800&auto=format&fit=crop&q=80","alt":"Modular Pegboard Wall Organizer (V7) Image 4","order":3},{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Modular Pegboard Wall Organizer (V7) Image 5","order":4}]'::jsonb, '["Nordic Birch plywood","4 modular shelves","8 wooden peg hooks","Includes heavy-duty wall anchors"]'::jsonb, '["Beautiful wooden grain aesthetic","Sturdy peg fittings","Endless configuration options"]'::jsonb, '["Installation requires drilling","Max load limit is 12kg"]'::jsonb, false, false, 2068, '2026-05-26T23:12:11.466Z', '2026-05-26T23:12:11.466Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000110', 'premium-faux-ivy-vine-strings-12-pack-v7', 'Premium Faux Ivy Vine Strings (12-pack) (V7)', 'Add a soft touch of greenery to your bedroom. 12 strands of realistic silk ivy vines, perfect for hanging over curtains, LED lights, or bedframes.', 'd10b7f8c-cbde-4e3a-b8ff-54a880f83d22', 'd10b7f8c-cbde-4e3a-b8ff-54a880f83d24', 570, 'COZY-PLANTS', '[{"url":"https://images.unsplash.com/photo-1513694203232-719a280e022f?w=600&auto=format&fit=crop&q=80","alt":"Premium Faux Ivy Vine Strings (12-pack) (V7) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Premium Faux Ivy Vine Strings (12-pack) (V7) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=600&auto=format&fit=crop&q=80","alt":"Premium Faux Ivy Vine Strings (12-pack) (V7) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800&auto=format&fit=crop&q=80","alt":"Premium Faux Ivy Vine Strings (12-pack) (V7) Image 4","order":3},{"url":"https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=600&auto=format&fit=crop&q=80","alt":"Premium Faux Ivy Vine Strings (12-pack) (V7) Image 5","order":4}]'::jsonb, '["Silk leaves with plastic stems","84 feet total length","High-fidelity texture printing","Comes with cable ties"]'::jsonb, '["Low cost room upgrade","Realistic leaf textures","No watering needed!"]'::jsonb, '["Initial plastic smell when unboxed","Leaves can fall off if handled roughly"]'::jsonb, false, true, 3259, '2026-05-27T05:24:32.120Z', '2026-05-27T05:24:32.120Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000111', 'oversized-heavy-iron-pump-cover-v7', 'Oversized ''Heavy Iron'' Pump Cover (V7)', '320GSM heavy interlock cotton drop-shoulder tee. Designed to fit extra large to retain warmth at the start of workouts, and hold its boxy shape.', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e33', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e51', 1380, 'IRON-CRAFT', '[{"url":"https://images.unsplash.com/photo-1517838277536-f5f99be501cd?w=600&auto=format&fit=crop&q=80","alt":"Oversized ''Heavy Iron'' Pump Cover (V7) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=600&auto=format&fit=crop&q=80","alt":"Oversized ''Heavy Iron'' Pump Cover (V7) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=600&auto=format&fit=crop&q=80","alt":"Oversized ''Heavy Iron'' Pump Cover (V7) Image 3","order":2}]'::jsonb, '["320GSM Interlock Cotton","Acid washed charcoal","Durable double-stitched hem","Cracked-print graphic logo"]'::jsonb, '["Durable thick fabric","Flattering oversized drape","Excellent sweat absorption"]'::jsonb, '["Feels heavy in peak summer heat","Takes up space in gym bags"]'::jsonb, false, false, 2471, '2026-05-29T02:11:24.864Z', '2026-05-29T02:11:24.864Z'),
  ('a3c8e42f-7c1a-47a2-bd32-000000000112', 'matte-black-stainless-shaker-v7', 'Matte Black Stainless Shaker (V7)', 'Double-walled vacuum insulated shaker cup. Keeps pre-workouts ice cold for 12 hours. Zero leakage, odor-resistant steel interior.', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e33', 'a10a8f8d-dbed-4e3a-b9ff-54b880f85e52', 1030, 'IRON-CRAFT', '[{"url":"https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=600&auto=format&fit=crop&q=80","alt":"Matte Black Stainless Shaker (V7) Image 1","order":0},{"url":"https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=600&auto=format&fit=crop&q=80","alt":"Matte Black Stainless Shaker (V7) Image 2","order":1},{"url":"https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=600&auto=format&fit=crop&q=80","alt":"Matte Black Stainless Shaker (V7) Image 3","order":2},{"url":"https://images.unsplash.com/photo-1517838277536-f5f99be501cd?w=600&auto=format&fit=crop&q=80","alt":"Matte Black Stainless Shaker (V7) Image 4","order":3}]'::jsonb, '["Double-wall vacuum insulation","Food-grade 304 Stainless steel","Leaking-proof flip cap","Embossed internal measurements"]'::jsonb, '["Keeps drinks cold forever","Zero plastic protein smell buildup","Satisfying snap lid closure"]'::jsonb, '["Not microwave or dishwasher safe","Outer paint can scratch against keys"]'::jsonb, false, true, 4913, '2026-05-28T03:30:02.201Z', '2026-05-28T03:30:02.201Z');
